// components/fields/Location.tsx

import React from 'react';
import type{FieldValues} from 'react-hook-form';

// Using your specified import paths
import type{ILocation, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {KitsInputLocation} from "../../../../_compat";

/**
 * Renders a location/address search input.
 * All logic is handled by the useFieldLogic hook, making this a simple, declarative component.
 */
export const Location = <T extends FieldValues>({
                                                    element,
                                                    control,
                                                    getValues,
                                                    fieldLogic, groupField
                                                }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        placeholder,
        isDisabled,
        hideError,
        isRequired,
        helperText,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    // 2. Cast the element to its specific type to access unique properties.
    const locationElement = element as ILocation<T>;
    const {
        apiKey,
        provider,
        countryISO,
        forceSelection = true, // Default to true as in the original
        onAddressClick,
    } = locationElement;

    // 3. The component is now only responsible for rendering the UI.
    return (
        <KitsInputLocation
            // --- Core react-hook-form props ---
            {...field} // Spreads `onChange`, `onBlur`, `value`, `ref`

            // --- Resolved props from useFieldLogic ---
            id={field.name}
            label={label}
            placeholder={placeholder}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            attached={attached}

            list={[]}
            // --- Props from the element definition ---
            api_key={apiKey}
            provider={provider}
            countryISO={countryISO}
            forceSelection={forceSelection}
            onAddressClick={(address)=>onAddressClick(address, groupField)}
            hideError={hideError}
            withFilter={true} // This was hardcoded in the original
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
        />
    );
};

export default Location;
